mapper.update:
UPDATE maintenance_record
relic_id = #{relicId}, maintenance_type = #{maintenanceType}, maintenance_date = #{maintenanceDate}, maintenance_content = #{maintenanceContent}, maintainer = #{maintainer}, remark = #{remark}, update_time = #{updateTime},
WHERE id = #{id}

mapper.select:
SELECT COUNT(1)
FROM maintenance_record
WHERE YEAR(maintenance_date) = #{year}
AND MONTH(maintenance_date) = #{month}

SELECT COUNT(1)
FROM maintenance_record
WHERE DATE(maintenance_date) BETWEEN #{startDate} AND #{endDate}
